import { useState, useEffect, useCallback } from "react"
import { PROMOTIONS } from "@/lib/constants/promotions"

export function PromoCarousel() {
  const [current, setCurrent] = useState(0)

  const next = useCallback(
    () => setCurrent((p) => (p + 1) % PROMOTIONS.length),
    [PROMOTIONS.length]
  )

  useEffect(() => {
    if (PROMOTIONS.length <= 1) return
    const t = setInterval(next, 5000)
    return () => clearInterval(t)
  }, [next, PROMOTIONS.length])

  if (PROMOTIONS.length === 0) return null

  const promo = PROMOTIONS[current]
  return (
    <a
      href={promo.ctaHref || "/promociones"}
      className="relative block bg-accent py-2 text-center text-sm font-medium text-accent-foreground transition-colors hover:bg-accent/90"
    >
      {promo.badge && (
        <span className="mr-2 inline-block rounded-full bg-white/20 px-2 py-0.5 text-xs font-bold">
          {promo.badge}
        </span>
      )}
      {promo.title}: {promo.description}
      {PROMOTIONS.length > 1 && (
        <span className="ml-2 text-accent-foreground/60">({current + 1}/{PROMOTIONS.length})</span>
      )}
    </a>
  )
}
