{"content":"import { NextRequest, NextResponse } from "next/server"
import { createAdminClient } from "@ai-whisperers/auth/supabase/server"

const CONFIG_KEY = "content_overrides"

export async function GET(request: NextRequest) {
  const { searchParams } = new URL(request.url)
  const path = searchParams.get("path")

  const supabase = createAdminClient()
  const { data } = await supabase
    .from("ej_site_config")
    .select("value")
    .eq("key", CONFIG_KEY)
    .single()

  const overrides = data?.value ?? {}

  // Return only overrides (no JSON defaults)
  if (path) {
    const value = deepGet(overrides, path)
    if (value === undefined) {
      return NextResponse.json({ error: `Path '${path}' not found` }, { status: 404 })
    }
    return NextResponse.json({ value })
  }

  return NextResponse.json(overrides)
}

function deepGet(obj: any, path: string): any {
  const parts = path.split(".")
  let cur = obj
  for (const p of parts) {
    if (cur?.[p] === undefined || cur?.[p] === null) return undefined
    cur = cur[p]
  }
  return cur
}
